elta) {\n+  if (!areAdjacent(islands, from, to)) {\n+    return { valid: false, error: ERR_NON_ADJ };\n+  }\n+\n+  const key = canonicalKey(from, to);\n+  const existing = bridges.get(key) || 0;\n+  const next = existing + delta;\n+  if (next < 0) return { valid: true, error: null };\n+  if (next > 2) return { valid: false, error: ERR_MAX2 };\n+\n+  // crossing check only when adding (> existing)\n+  if (delta > 0) {\n+    // Temporarily consider the segment exists (even if it already exists, crossing would\n+    // already be present, but we still prevent adding into crossing situations).\n+    if (wouldCrossExisting(bridges, from, to)) {\n+      return { valid: false, error: ERR_CROSS };\n+    }\n+  }\n+\n+  // Island count exceed check\n+  const counts = computeCurrentCounts(islands, bridges);\n+  const fromIsland = islands.find((i) => i.x === from.x && i.y === from.y) || from;\n+  const toIsland = islands.find((i) => i.x === to.x && i.y === to.y) || to;\n+\n+  const fromCount = counts.get(fromIsland.id) || 0;\n+  const toCount = counts.get(toIsland.id) || 0;\n+\n+  if (delta > 0) {\n+    if (fromCount + delta > fromIsland.value || toCount + delta > toIsland.value) {\n+      return { valid: false, error: ERR_EXCEED };\n+    }\n+  }\n+\n+  return { valid: true, error: null };\n+}\n+\n+export function checkConnectivity(islands, bridges) {\n+  if (islands.length <= 1) return true;\n+  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));\n+\n+  const adj = new Map(islands.map((i) => [i.id, new Set()]));\n+  for (const [key, n] of bridges.entries()) {\n+    if (!n) continue;\n+    const { x1, y1, x2, y2 } = parseKey(key);\n+    const a = byCoord.get(`${x1},${y1}`);\n+    const b = byCoord.get(`${x2},${y2}`);\n+    if (!a || !b) continue;\n+    adj.get(a.id).add(b.id);\n+    adj.get(b.id).add(a.id);\n+  }\n+\n+  const start = islands[0].id;\n+  const seen = new Set([start]);\n+  const queue = [start];\n+  while (queue.length) {\n+    const cur = queue.shi